sys_hub_flow.latest_snapshot:
{
    "name": "x_casemgmt_validate_closed_transition",
    "label": "Validate Closed Transition",
    "type": "subflow",
    "description": "Validates the Resolved -> Closed transition. Requires caller to have x_casemgmt_case_manager role; throws 'Only case managers can close cases.' on failure (AAP Section 0.5.5). On success, sets closed_date = gs.nowDateTime() on the case row.",
    "scope": "x_casemgmt",
    "run_as": "caller",
    "category": "subflow",
    "inputs": [
        {
            "id": "input_case_record",
            "name": "case_record",
            "label": "Case Record",
            "field_type": "reference",
            "reference_table": "x_casemgmt_case",
            "is_mandatory": true,
            "default_value": null,
            "description": "The x_casemgmt_case row whose Closed-transition is being validated. Passed from the parent flow as $trigger.current. The Script Include validates the saving user has the case_manager role; on success, the Update Record step sets closed_date on this record."
        }
    ],
    "outputs": [],
    "stages": [],
    "actions": [
        {
            "id": "step_run_validator",
            "order": 100,
            "name": "Validate Closed Transition (manager role check)",
            "type": "script_step",
            "description": "Calls x_casemgmt.CaseTransitionValidator.canTransitionToClosed(case_record, gs.getUserID()). The Script Include returns { ok: true } when the user has the x_casemgmt_case_manager role, or { ok: false, error: 'Only case managers can close cases.' } when the role check fails. Also captures gs.nowDateTime() as closed_date_now for the subsequent Update Record step (Step 3). Passing gs.getUserID() explicitly ensures the role check evaluates against the saving user (defensive; matches the validator's signature).",
            "script": "(function execute(inputs, outputs) { var validator = new x_casemgmt.CaseTransitionValidator(); var result = validator.canTransitionToClosed(inputs.case_record, gs.getUserID()); outputs.ok = !!(result && result.ok); outputs.error_message = (result && result.error) ? String(result.error) : ''; outputs.closed_date_now = gs.nowDateTime() + ''; })(fd_data.subflow_inputs, fd_data._step_outputs);",
            "script_includes_used": [
                "x_casemgmt.CaseTransitionValidator"
            ],
            "tables_referenced": [],
            "outputs": [
                {
                    "name": "ok",
                    "label": "OK",
                    "field_type": "boolean",
                    "description": "True when the validator reports the saving user has the x_casemgmt_case_manager role. False when the role check fails or when the case_record input is null/undefined."
                },
                {
                    "name": "error_message",
                    "label": "Error Message",
                    "field_type": "string",
                    "description": "Empty string when ok=true. The Script Include's default message 'Only case managers can close cases.' when ok=false because of a missing case_manager role. The defensive message 'Case record is missing.' when ok=false because of a null case_record (should not occur in normal parent-flow invocation)."
                },
                {
                    "name": "closed_date_now",
                    "label": "Closed Date Now",
                    "field_type": "string",
                    "description": "Current GlideDateTime in system timezone, captured at the moment the validator was called. Bound to the Update Record step's closed_date field via ${step_run_validator.closed_date_now}. Equivalent to ArkCase ChangeCaseFileStateService line 93's 'Date now = new Date()' followed by line 99's retval.setClosed(now)."
                }
            ]
        },
        {
            "id": "step_if_validator_failed",
            "order": 200,
            "name": "If validator returned not-ok",
            "type": "if",
            "description": "Branches when the validator's ok output is false. The branch executes the Throw Error action that surfaces the validator's error message on the form and aborts the parent flow's triggering update transaction.",
            "condition": "fd_data._step_outputs.step_run_validator.ok == false",
            "actions": [
                {
                    "id": "step_throw_error",
                    "order": 100,
                    "name": "Throw Error (surface validator message)",
                    "type": "throw_error",
                    "description": "Throws the validator's error message to abort the parent flow's update and surface the message on the form. Flow Designer Throw Error implicitly invokes gs.addErrorMessage(message) and setAbortAction(true) on the triggering GlideRecord transaction. The message is bound to the Script Step's error_message output, which the Script Include sets to 'Only case managers can close cases.' when the role check fails. The default message 'Only case managers can close cases.' is preserved character-for-character including trailing period and lowercase 'managers' / 'cases' per the Script Include's canonical message.",
                    "inputs": {
                        "message": "${step_run_validator.error_message}",
                        "default_validator_message": "Only case managers can close cases."
                    }
                }
            ]
        },
        {
            "id": "step_update_closed_date",
            "order": 300,
            "name": "Set closed_date to now (success path)",
            "type": "update_record",
            "description": "On the success path (validator ok=true and Throw Error did not fire), updates the case_record's closed_date field to gs.nowDateTime() captured by Step 1's closed_date_now output. This is the AAP Section 0.5.5 mandated side effect of the Resolved -> Closed transition. The companion business rule ../../business_rules/x_casemgmt_set_closed_date.xml provides defense-in-depth (sets the same field at the BR layer with the same gs.nowDateTime() expression). ServiceNow-native equivalent of ArkCase ChangeCaseFileStateService line 99: retval.setClosed(now).",
            "condition": "fd_data._step_outputs.step_run_validator.ok == true",
            "inputs": {
                "table": "x_casemgmt_case",
                "record": "${inputs.case_record}",
                "fields": [
                    {
                        "field_name": "closed_date",
                        "value": "${step_run_validator.closed_date_now}"
                    }
                ]
            }
        }
    ]
}

